const stories = $input.all().map(item => item.json);

  // Format stories for the prompt
 const formatted = stories.map((story, index) => {
    const hoursOld = story.hours_old || 'Unknown';
    const source = story.source || 'Unknown Source';
    return `Story ${index + 1}:
    Title: ${story.title}
    Summary: ${story.summary}
    Published: ${story.pubDate}
    Hours Old: ${hoursOld}
    Source: ${source}`;
  }).join('\n\n');

  return [{
    json: {
      stories: stories,
      promptText: formatted,
      storyCount: stories.length,
      timestamp: new Date().toISOString()
    }
  }]

