// Normalize LLM output to a consistent root-level object.
// Supports: structured under "output", structured at root, or legacy raw text.

let data = null;

// 1) Structured under "output" (current behavior with Output Parser ON)
if ($json.output && typeof $json.output === 'object') {
  data = $json.output;

// 2) Structured at root (in case parser returns directly)
} else if ($json.selected_story && $json.all_stories_scoring && typeof $json.selection_reason === 'string') {
  data = $json;

// 3) Legacy: raw JSON string in $json.text (fallback path)
} else if (typeof $json.text === 'string' && $json.text.trim()) {
  let s = $json.text;

  // Remove code fences if present
  if (s.startsWith('```')) {
    const m = s.match(/```(?:json)?\s*([\s\S]*?)\s*```/i);
    if (m) s = m[1];
  }

  // Remove illegal backslashes before smart quotes
  s = s.replace(/\\(?=[“”’])/g, '');

  // Fix newlines between key and value (":" followed by newline)
  s = s.replace(/:\s*\n\s*/g, ': ');

  // Clamp to outermost braces
  const start = s.indexOf('{');
  const end = s.lastIndexOf('}');
  if (start >= 0 && end > start) s = s.slice(start, end + 1);

  // Parse with one common repair for unclosed all_stories_scoring
  try {
    data = JSON.parse(s);
  } catch (e) {
    if (/"all_stories_scoring"\s*:\s*\[[\s\S]*\}\s*$/.test(s) && !/\]\s*\}\s*$/.test(s)) {
      s = s.replace(/\}\s*$/, "]\n}"); // close the array then the object
    }
    data = JSON.parse(s); // will throw if still invalid
  }

} else {
  throw new Error('Upstream did not provide structured JSON or text to parse. Keys present: ' + Object.keys($json).join(', '));
}

// Validate required top-level keys
if (!data.selected_story || !Array.isArray(data.all_stories_scoring) || typeof data.selection_reason !== 'string') {
  throw new Error('Missing required keys after normalization. Present keys: ' + Object.keys(data).join(', '));
}

// Deep validation for selected_story
const reqSel = ["title","summary","source","story_number","hours_old","emotional_impact","global_relevance","specificity","total_score","verification"];
const missingSel = reqSel.filter(k => !(k in data.selected_story));
if (missingSel.length) {
  throw new Error('selected_story missing fields: ' + missingSel.join(', '));
}

return { json: data };
